using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: returns JsonTypeInfo<Person> directly
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// Round-trip using the typed metadata
var json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"Deserialized: {deserialized}");

// 2) Probe without throwing using TryGetTypeInfo
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"\nTryGetTypeInfo(Person) succeeded: {info!.Type.Name}");
}

// Now try a type the resolver doesn't know about (empty resolver → no metadata)
var emptyOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new EmptyResolver()
};

if (emptyOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing))
{
    Console.WriteLine($"Unexpected: got metadata for Person");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo(Person) on empty resolver returned false — no exception thrown.");
}

// --- Types ---

public record Person(string Name, int Age);

// A resolver that never provides metadata for anything
file sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

